import React, { useState } from 'react';
import { Container, Typography, Box, Card, CardContent, Chip, Button, TextField, LinearProgress } from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import { C } from '../theme';

const checkInPrompts = [
  { q: "What is the ONE thing you accomplished today that matters most?", type: "text" },
  { q: "What did you struggle with today and what did it teach you?", type: "text" },
  { q: "Rate your energy level today (1–10)", type: "scale", min: 1, max: 10 },
  { q: "Rate your focus level today (1–10)", type: "scale", min: 1, max: 10 },
  { q: "Did you do something today that moved you closer to your goals?", type: "yesno" },
  { q: "What will you do differently tomorrow?", type: "text" },
];

export default function Checkin() {
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const completed = Object.keys(answers).length;
  const progress = (completed / checkInPrompts.length) * 100;

  const setAnswer = (i, val) => setAnswers({ ...answers, [i]: val });

  if (submitted) {
    const energy = answers[2] || 5;
    const focus = answers[3] || 5;
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Card sx={{ borderRadius: 3, overflow: 'hidden' }}>
          <Box sx={{ background: C.heroGrad, p: 4, textAlign: 'center' }}>
            <CheckCircleIcon sx={{ fontSize: 64, color: C.greenLight, mb: 1 }} />
            <Typography variant="h4" fontWeight={800} sx={{ color: C.pearl }}>Check-in Complete!</Typography>
            <Typography sx={{ color: 'rgba(245,240,232,0.7)', mt: 1 }}>You showed up for yourself today. That's what it takes.</Typography>
          </Box>
          <CardContent sx={{ p: 4 }}>
            <Typography variant="h6" fontWeight={700} sx={{ color: C.purple, mb: 3 }}>Today's Summary</Typography>
            <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
              {[{ label: 'Energy', val: energy }, { label: 'Focus', val: focus }].map(s => (
                <Box key={s.label} sx={{ flex: 1, p: 2.5, borderRadius: 2, bgcolor: C.pearl, border: `1px solid ${C.cardBorder}`, textAlign: 'center' }}>
                  <Typography variant="h3" fontWeight={800} sx={{ color: s.val >= 7 ? C.green : s.val >= 5 ? C.warning : C.error }}>{s.val}/10</Typography>
                  <Typography variant="caption" sx={{ color: C.greyBlue, fontWeight: 600 }}>{s.label}</Typography>
                </Box>
              ))}
            </Box>
            <Box sx={{ p: 2.5, borderRadius: 2, bgcolor: C.pearl, border: `1px solid ${C.cardBorder}`, mb: 2 }}>
              <Typography variant="overline" sx={{ color: C.greyBlue, letterSpacing: 2 }}>Your Win Today</Typography>
              <Typography sx={{ color: C.purple, mt: 0.5, fontWeight: 500 }}>{answers[0] || '—'}</Typography>
            </Box>
            <Box sx={{ p: 2.5, borderRadius: 2, bgcolor: C.pearl, border: `1px solid ${C.cardBorder}` }}>
              <Typography variant="overline" sx={{ color: C.greyBlue, letterSpacing: 2 }}>Tomorrow's Intention</Typography>
              <Typography sx={{ color: C.purple, mt: 0.5, fontWeight: 500 }}>{answers[5] || '—'}</Typography>
            </Box>
            <Button variant="contained" fullWidth onClick={() => { setAnswers({}); setSubmitted(false); }}
              sx={{ mt: 3, py: 1.5, bgcolor: C.green, '&:hover': { bgcolor: C.greenDark } }}>
              New Check-in
            </Button>
          </CardContent>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Box sx={{ mb: 4 }}>
        <Typography variant="h4" fontWeight={800} sx={{ color: C.purple }}>✅ Daily Check-in</Typography>
        <Typography sx={{ color: C.greyBlue, mt: 0.5 }}>5 minutes. Every day. This is how you build self-awareness.</Typography>
      </Box>

      {/* Progress */}
      <Box sx={{ mb: 4, p: 2.5, borderRadius: 3, bgcolor: C.pearl, border: `1px solid ${C.cardBorder}` }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
          <Typography variant="body2" fontWeight={600} sx={{ color: C.purple }}>{completed} of {checkInPrompts.length} answered</Typography>
          <Typography variant="body2" sx={{ color: C.green, fontWeight: 700 }}>{Math.round(progress)}%</Typography>
        </Box>
        <LinearProgress variant="determinate" value={progress}
          sx={{ height: 8, borderRadius: 4, bgcolor: 'rgba(71,133,89,0.15)', '& .MuiLinearProgress-bar': { bgcolor: C.green } }} />
      </Box>

      {checkInPrompts.map((prompt, i) => (
        <Card key={i} sx={{ borderRadius: 3, mb: 2, border: `1px solid ${answers[i] !== undefined ? C.green : C.cardBorder}`,
          bgcolor: answers[i] !== undefined ? `rgba(71,133,89,0.04)` : C.white }}>
          <CardContent sx={{ p: 3 }}>
            <Box sx={{ display: 'flex', gap: 2, alignItems: 'flex-start' }}>
              <Box sx={{ minWidth: 28, height: 28, borderRadius: '50%',
                bgcolor: answers[i] !== undefined ? C.green : C.pearl,
                border: `2px solid ${answers[i] !== undefined ? C.green : C.cardBorder}`,
                display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {answers[i] !== undefined
                  ? <CheckCircleIcon sx={{ color: C.white, fontSize: 16 }} />
                  : <Typography sx={{ color: C.greyBlue, fontWeight: 700, fontSize: '0.75rem' }}>{i + 1}</Typography>}
              </Box>
              <Box sx={{ flex: 1 }}>
                <Typography fontWeight={700} sx={{ color: C.purple, mb: 1.5 }}>{prompt.q}</Typography>
                {prompt.type === 'text' && (
                  <TextField multiline rows={2} fullWidth placeholder="Your answer..."
                    value={answers[i] || ''}
                    onChange={e => setAnswer(i, e.target.value)}
                    sx={{ '& .MuiOutlinedInput-root': { borderRadius: 2, bgcolor: C.white,
                      '& fieldset': { borderColor: C.cardBorder },
                      '&:hover fieldset': { borderColor: C.green },
                      '&.Mui-focused fieldset': { borderColor: C.green } } }} />
                )}
                {prompt.type === 'scale' && (
                  <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
                    {Array.from({ length: prompt.max - prompt.min + 1 }, (_, k) => k + prompt.min).map(n => (
                      <Box key={n} onClick={() => setAnswer(i, n)} sx={{
                        width: 42, height: 42, borderRadius: 2, cursor: 'pointer',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        bgcolor: answers[i] === n ? C.green : C.pearl,
                        border: `2px solid ${answers[i] === n ? C.green : C.cardBorder}`,
                        color: answers[i] === n ? C.white : C.purple,
                        fontWeight: 700, transition: 'all 0.15s',
                        '&:hover': { bgcolor: answers[i] === n ? C.greenDark : 'rgba(71,133,89,0.15)' }
                      }}>{n}</Box>
                    ))}
                  </Box>
                )}
                {prompt.type === 'yesno' && (
                  <Box sx={{ display: 'flex', gap: 2 }}>
                    {['Yes ✓', 'No ✗'].map(opt => (
                      <Button key={opt} variant={answers[i] === opt ? 'contained' : 'outlined'}
                        onClick={() => setAnswer(i, opt)}
                        sx={{ flex: 1, py: 1.2, fontWeight: 700,
                          bgcolor: answers[i] === opt ? (opt.includes('Yes') ? C.green : C.error) : 'transparent',
                          borderColor: opt.includes('Yes') ? C.green : C.error,
                          color: answers[i] === opt ? C.white : (opt.includes('Yes') ? C.green : C.error),
                          '&:hover': { bgcolor: opt.includes('Yes') ? C.greenDark : '#6b1d27', color: C.white } }}>
                        {opt}
                      </Button>
                    ))}
                  </Box>
                )}
              </Box>
            </Box>
          </CardContent>
        </Card>
      ))}

      <Button variant="contained" fullWidth disabled={completed < checkInPrompts.length}
        onClick={() => setSubmitted(true)}
        sx={{ mt: 2, py: 1.8, fontSize: '1rem', fontWeight: 700,
          bgcolor: C.green, '&:hover': { bgcolor: C.greenDark },
          '&.Mui-disabled': { bgcolor: 'rgba(71,133,89,0.2)', color: C.greyBlue } }}>
        {completed < checkInPrompts.length ? `Answer all ${checkInPrompts.length} questions to submit` : '✅ Submit Today\'s Check-in'}
      </Button>
    </Container>
  );
}
